// ──────────────────────────────────────────────
// Execute updates
// ──────────────────────────────────────────────
$updated = 0;
$fixed   = 0;

foreach ($tourTypes as $slug => $data) {
    $tourType = TourType::where('slug', $slug)->first();
    if (!$tourType) {
        echo "⚠ Tour type '{$slug}' not found — skipped.\n";
        continue;
    }

    $tourType->update([
        'description'              => $data['description'],
        'meta_title'               => $data['meta_title'],
        'meta_description'         => $data['meta_description'],
        'meta_keywords'            => $data['meta_keywords'],
        'description_translations' => $data['description_translations'],
    ]);

    echo "✓ Updated: {$tourType->name}\n";
    $updated++;
}

// Also fix any remaining ??? in tour_types table
$fixCount = \Illuminate\Support\Facades\DB::table('tour_types')
    ->where('description', 'like', '%???%')
    ->update(['description' => \Illuminate\Support\Facades\DB::raw("REPLACE(description, '???', '—')")]);
$fixed += $fixCount;

echo "\n══════════════════════════════════\n";
echo "Updated: {$updated} tour types\n";
echo "Fixed ???: {$fixed} rows\n";
echo "══════════════════════════════════\n";
